import React, {useEffect, useMemo, useState} from 'react';
import { createRoot } from 'react-dom/client';
import { Activity, AlertTriangle, Bell, Boxes, CheckCircle2, ChevronRight, CircleDot, Clipboard, Copy, Download, Filter, Gauge, GitBranch, Globe2, HardDriveDownload, LifeBuoy, Lock, Moon, Network, Play, Plus, RefreshCw, Rocket, Save, Search, Server, Settings, ShieldCheck, Sun, Square, TerminalSquare, Trash2, Upload, Wifi, X, Zap } from 'lucide-react';
import './styles.css';

const NAV=[['dash','总览',Gauge,'运行、节点与网络状态总控'],['nodes','节点',Network,'代理节点资产与健康详情'],['network','网络模式',Wifi,'SOCKS/HTTP 推荐，TUN 手动确认'],['traffic','流量',Activity,'实时统计、入站与节点流量'],['enhance','增强',Zap,'自动选优、通知和趋势'],['diagnose','诊断',LifeBuoy,'TUN 诊断、安全向导和诊断包'],['logs','日志',TerminalSquare,'实时运行日志中心'],['backup','备份',HardDriveDownload,'导入、导出和恢复'],['settings','设置',Settings,'版本、会话和偏好']];
const navMeta=Object.fromEntries(NAV.map(([id,title,Icon,sub])=>[id,{title,Icon,sub}]));
const tokenKey='xray_token', refreshKey='xray_refresh';
const fmtBytes=n=>{n=Number(n)||0;if(n<1024)return n+' B';if(n<1048576)return(n/1024).toFixed(1)+' KB';if(n<1073741824)return(n/1048576).toFixed(1)+' MB';return(n/1073741824).toFixed(2)+' GB'};
const proto=n=>n?.protocol||'-'; const addr=n=>n?.settings?.vnext?.[0]?.address||n?.settings?.servers?.[0]?.address||'-'; const port=n=>n?.settings?.vnext?.[0]?.port||n?.settings?.servers?.[0]?.port||'-'; const uid=n=>n?.settings?.vnext?.[0]?.users?.[0]?.id||n?.settings?.servers?.[0]?.password||'';
function systemOnly(n){let t=n?.tag,p=n?.protocol;return ['direct','block','api'].includes(t)||(['freedom','blackhole','dns'].includes(p)&&t!=='proxy')}
function StatusPill({state,children}){return <span className={'statusPill '+(state||'') }><i/> {children}</span>}
function Button({kind='',size='',icon:Icon,children,...props}){return <button className={`btn ${kind} ${size}`} {...props}>{Icon&&<Icon size={16}/>}<span>{children}</span></button>}
function Card({title,sub,icon:Icon,action,children,className=''}){return <section className={'card '+className}><header className="cardHead"><div>{Icon&&<span className="cardIcon"><Icon size={17}/></span>}<div><h2>{title}</h2>{sub&&<p>{sub}</p>}</div></div>{action}</header><div className="cardBody">{children}</div></section>}
function Empty({title='暂无数据',sub='完成配置后会显示在这里。'}){return <div className="emptyState"><CircleDot size={28}/><b>{title}</b><span>{sub}</span></div>}
function Field({label,children,wide=false}){return <label className={'field '+(wide?'wide':'')}><span>{label}</span>{children}</label>}
function ToggleField({label,sub,checked,onChange}){return <label className="toggleField"><span><b>{label}</b>{sub&&<em>{sub}</em>}</span><input type="checkbox" checked={checked} onChange={onChange}/></label>}
function App(){
  const [token,setToken]=useState(localStorage.getItem(tokenKey)||''); const [setup,setSetup]=useState(false); const [authed,setAuthed]=useState(false); const [loginErr,setLoginErr]=useState(''); const [pwd,setPwd]=useState('');
  const [view,setView]=useState('dash'); const [toast,setToast]=useState(''); const [foot,setFoot]=useState('就绪'); const [busy,setBusy]=useState(false);
  const [status,setStatus]=useState({}); const [nodes,setNodes]=useState([]); const [allNodes,setAllNodes]=useState([]); const [sel,setSel]=useState(null); const [tun,setTun]=useState({config:{}}); const [traffic,setTraffic]=useState({}); const [history,setHistory]=useState([]); const [logs,setLogs]=useState(''); const [auto,setAuto]=useState({config:{}}); const [notify,setNotify]=useState({config:{channels:{}}}); const [notifyLog,setNotifyLog]=useState([]); const [trend,setTrend]=useState({}); const [diag,setDiag]=useState(null); const [tunBak,setTunBak]=useState('');
  const [nodeModal,setNodeModal]=useState(false); const [importModal,setImportModal]=useState(false); const [nodeForm,setNodeForm]=useState({tag:'',protocol:'vless',address:'',port:'443',id:'',network:'tcp',security:'tls',extra:''}); const [importText,setImportText]=useState(''); const [importPreview,setImportPreview]=useState(null); const [importTest,setImportTest]=useState(true);
  const [tunForm,setTunForm]=useState({name:'tun0',MTU:1500,gateway:'172.19.0.1',DNS:'8.8.8.8,1.1.1.1',autoOutboundsInterface:'',autoStart:'false'}); const [tunIfaces,setTunIfaces]=useState([]);
  const [autoForm,setAutoForm]=useState({enabled:false,stableCount:3,minInterval:30,avgWindow:5,maxLatency:5000}); const [notifyForm,setNotifyForm]=useState({tg:false,tgToken:'',tgChat:'',wx:false,wxUrl:'',sc:false,scKey:''}); const [bakPwd,setBakPwd]=useState(''); const [bakPwd2,setBakPwd2]=useState(''); const [bakFile,setBakFile]=useState(null); const [bakPreview,setBakPreview]=useState(null);
  const [theme,setTheme]=useState(()=>localStorage.getItem('xray_theme')||'light');
  const [nodeSearch,setNodeSearch]=useState(''); const [nodeSort,setNodeSort]=useState('default');
  const [nodeChecked,setNodeChecked]=useState(new Set());
  const [nodeLatency,setNodeLatency]=useState({});
  const [nodeLabels,setNodeLabels]=useState({});
  const [logSearch,setLogSearch]=useState(''); const [logAutoScroll,setLogAutoScroll]=useState(true);
  const [trafficRange,setTrafficRange]=useState(24);
  const [subscriptions,setSubscriptions]=useState([]);
  const [quota,setQuota]=useState({enabled:false,monthly_gb:100,notify_at:[80,100],reset_day:1});
  const [quotaStatus,setQuotaStatus]=useState(null);
  const [routingRules,setRoutingRules]=useState([]); const [routingDomainStrategy,setRoutingDomainStrategy]=useState('IPIfNonMatch');
  const [geoStatus,setGeoStatus]=useState(null);
  const [curlResult,setCurlResult]=useState(null);
  const [confirmTun,setConfirmTun]=useState(null);
  const [subModal,setSubModal]=useState(false);
  function flash(m){setToast(m);setTimeout(()=>setToast(''),2600)}
  async function api(path,opt={}){let r=await fetch(path,{...opt,headers:{'Content-Type':'application/json',...(token?{Authorization:'Bearer '+token}:{}),...(opt.headers||{})}});let d=await r.json().catch(()=>({ok:false,error:'非 JSON 响应'}));if(r.status===401&&!path.startsWith('/api/auth/')){logout();throw Error('登录已过期，请重新输入密码')}if(!r.ok||d.ok===false)throw Error(d.error||('HTTP '+r.status));return d}
  function logout(){localStorage.removeItem(tokenKey);localStorage.removeItem(refreshKey);setToken('');setAuthed(false)}
  useEffect(()=>{fetch('/api/auth/status').then(r=>r.json()).then(s=>{let need=s.status==='setup_needed'||s.hasPassword===false;setSetup(need); if(token){setAuthed(true)} }).catch(()=>{if(token)setAuthed(true)})},[]);
  useEffect(()=>{if(authed) refreshAll()},[authed]);
  useEffect(()=>{document.documentElement.setAttribute('data-theme',theme);localStorage.setItem('xray_theme',theme)},[theme]);
  async function saveLabels(nodeTag,labels){try{await api('/api/ext/tags/'+encodeURIComponent(nodeTag),{method:'PUT',body:JSON.stringify({labels})});setNodeLabels(p=>({...p,[nodeTag]:labels}));flash('标签已保存')}catch(e){flash(e.message)}}
  async function addSub(name,url,interval_hours){try{await api('/api/ext/subscriptions',{method:'POST',body:JSON.stringify({name,url,interval_hours})});flash('已添加订阅');loadExt()}catch(e){flash(e.message)}}
  async function runSub(id){try{const r=await api('/api/ext/subscriptions/'+id+'/run',{method:'POST'});flash(r.ok?'已添加 '+(r.added||0)+' 个节点':(r.error||'更新失败'));refreshAll()}catch(e){flash(e.message)}}
  async function delSub(id){if(!confirm('删除订阅？'))return;try{await api('/api/ext/subscriptions/'+id,{method:'DELETE'});flash('已删除');loadExt()}catch(e){flash(e.message)}}
  async function saveQuota(){try{await api('/api/ext/quota',{method:'POST',body:JSON.stringify(quota)});flash('已保存配额')}catch(e){flash(e.message)}}
  async function saveRouting(){try{await api('/api/ext/routing',{method:'POST',body:JSON.stringify({rules:routingRules,domainStrategy:routingDomainStrategy})});flash('路由规则已保存');refreshAll()}catch(e){flash(e.message)}}
  async function updateGeo(){try{setFoot('下载 Geo 数据…');const r=await api('/api/ext/geo/update',{method:'POST'});flash(r.hint||'已更新');loadExt();setFoot('就绪')}catch(e){flash(e.message);setFoot('就绪')}}
  async function curlTest(target,mode){try{setCurlResult({pending:true});const r=await api('/api/ext/curl-test',{method:'POST',body:JSON.stringify({target,mode})});setCurlResult(r)}catch(e){setCurlResult({ok:false,error:e.message})}}
  async function batchToggle(enable){const tags=[...nodeChecked];if(!tags.length){flash('请先选择节点');return}try{const r=await api('/api/nodes/batch',{method:'POST',body:JSON.stringify({action:enable?'enable':'disable',tags})});setNodeChecked(new Set());flash('批量操作完成：'+(r.results?.filter(x=>x.ok).length||0)+'/'+tags.length);refreshAll()}catch(e){flash(e.message)}}
  async function batchDelete(){const tags=[...nodeChecked];if(!tags.length){flash('请先选择节点');return}if(!confirm('确认删除 '+tags.length+' 个节点？'))return;try{const r=await api('/api/nodes/batch',{method:'POST',body:JSON.stringify({action:'delete',tags})});setNodeChecked(new Set());flash('批量删除完成：'+(r.results?.filter(x=>x.ok).length||0)+'/'+tags.length);refreshAll()}catch(e){flash(e.message)}}
  function copyText(t){navigator.clipboard?.writeText(t).then(()=>flash('已复制：'+t)).catch(()=>flash('复制失败'))}
  async function moveNode(fromIdx,toIdx){const real=[...nodes];const item=real.splice(fromIdx,1)[0];real.splice(toIdx,0,item);const allOrder=[...allNodes.filter(n=>systemOnly(n)),...real].map(n=>n.tag);try{await api('/api/nodes/reorder',{method:'POST',body:JSON.stringify({tags:allOrder})});flash('排序已保存');refreshAll()}catch(e){flash(e.message)}}
  async function testNodeWithLatency(tag){try{const r=await api('/api/nodes/'+encodeURIComponent(tag)+'/test',{method:'POST'});setNodeLatency(p=>({...p,[tag]:r.ok?r.ms:'fail'}));flash(r.ok?(tag+': '+r.ms+'ms'):(tag+': '+(r.error||'失败')))}catch(e){flash(e.message)}}
  async function login(){if(!pwd.trim())return; setLoginErr(''); try{let d=await api(setup?'/api/auth/setup':'/api/auth/login',{method:'POST',body:JSON.stringify({password:pwd.trim()})}); if(!d.token)throw Error('登录成功但服务端未返回 token'); localStorage.setItem(tokenKey,d.token); if(d.refresh_token)localStorage.setItem(refreshKey,d.refresh_token); setToken(d.token); setPwd(''); setAuthed(true)}catch(e){setLoginErr(e.message||'登录失败')}}
  async function refreshAll(){setBusy(true);setFoot('刷新中…');await Promise.allSettled([loadStatus(),loadNodes(),loadTun(),loadTraffic(),loadLogs(),loadEnhance(),loadDiagnose(),loadExt()]);setFoot('就绪');setBusy(false)}
  async function loadExt(){try{const [t,sub,q,qs,r,g]=await Promise.all([api('/api/ext/tags'),api('/api/ext/subscriptions'),api('/api/ext/quota'),api('/api/ext/quota/check').catch(()=>({enabled:false})),api('/api/ext/routing'),api('/api/ext/geo/status')]);setNodeLabels(t.tags||{});setSubscriptions(sub.items||[]);setQuota(q.config||{enabled:false,monthly_gb:100,notify_at:[80,100],reset_day:1});setQuotaStatus(qs);setRoutingRules(r.rules||[]);setRoutingDomainStrategy(r.domainStrategy||'IPIfNonMatch');setGeoStatus(g)}catch(e){}}
  async function loadStatus(){try{setStatus(await api('/api/status'))}catch{setStatus({unknown:true})}}
  async function runAction(a){try{setFoot(a+'...');await api('/api/'+a,{method:'POST'});flash('操作完成');setTimeout(refreshAll,900)}catch(e){flash(e.message);setFoot('操作失败')}}
  async function loadNodes(){try{let d=await api('/api/nodes');let all=d.nodes||[], real=all.filter(n=>!systemOnly(n));setAllNodes(all);setNodes(real);setSel(s=> real.find(n=>n.tag===s?.tag)||real[0]||null)}catch(e){flash('节点加载失败：'+e.message)}}
  async function saveNode(){try{let extra=nodeForm.extra.trim()?JSON.parse(nodeForm.extra):{};let pt=parseInt(nodeForm.port,10);let node={tag:nodeForm.tag.trim(),protocol:nodeForm.protocol,settings:{},streamSettings:{network:nodeForm.network||'tcp',security:nodeForm.security||'none'},...extra};if(!node.tag||!nodeForm.address.trim()||!pt)throw Error('tag/地址/端口必填');if(['vless','vmess'].includes(node.protocol))node.settings={vnext:[{address:nodeForm.address.trim(),port:pt,users:[{id:nodeForm.id.trim(),alterId:0,encryption:'none'}]}]};else if(node.protocol==='trojan')node.settings={servers:[{address:nodeForm.address.trim(),port:pt,password:nodeForm.id.trim()}]};else node.settings={servers:[{address:nodeForm.address.trim(),port:pt,password:nodeForm.id.trim(),method:'aes-128-gcm'}]};await api(sel?('/api/nodes/'+encodeURIComponent(sel.tag)):'/api/nodes',{method:sel?'PUT':'POST',body:JSON.stringify(node)});setNodeModal(false);flash('节点已保存');loadNodes()}catch(e){flash(e.message)}}
  function openNode(n=null){setSel(n);setNodeForm(n?{tag:n.tag||'',protocol:proto(n),address:addr(n),port:String(port(n)||443),id:uid(n),network:n.streamSettings?.network||'tcp',security:n.streamSettings?.security||'none',extra:''}:{tag:'',protocol:'vless',address:'',port:'443',id:'',network:'tcp',security:'tls',extra:''});setNodeModal(true)}
  async function toggleNode(tag,en){try{await api('/api/nodes/'+encodeURIComponent(tag)+'/toggle',{method:'POST',body:JSON.stringify({enabled:en})});loadNodes()}catch(e){flash(e.message)}}
  async function delNode(tag){if(!confirm('删除节点 '+tag+' ?'))return;try{await api('/api/nodes/'+encodeURIComponent(tag),{method:'DELETE'});setSel(null);flash('已删除');loadNodes()}catch(e){flash(e.message)}}
  async function testNode(tag){try{let d=await api('/api/nodes/'+encodeURIComponent(tag)+'/test',{method:'POST'});flash(d.ms?`延迟 ${d.ms}ms`:(d.latency?`延迟 ${d.latency}ms`:'测试完成'));loadNodes()}catch(e){flash(e.message)}}
  async function testAll(){try{flash('开始批量测速');const r=await api('/api/nodes/test-all',{method:'POST',body:'{}'});const lat={};(r.results||[]).forEach(x=>{lat[x.tag]=x.ok?x.ms:'fail'});setNodeLatency(p=>({...p,...lat}));flash('测速完成：'+(r.results?.length||0)+' 个');loadNodes()}catch(e){flash(e.message)}}
  async function previewImport(){try{if(!importText.trim())return flash('请先粘贴节点链接或订阅 URL');setImportPreview(await api('/api/nodes/import',{method:'POST',body:JSON.stringify({text:importText.trim(),mode:'preview',duplicate:'rename'})}))}catch(e){flash(e.message)}}
  async function importLinks(){try{if(!importText.trim())return flash('请先粘贴节点链接或订阅 URL');let r=await api('/api/nodes/import',{method:'POST',body:JSON.stringify({text:importText.trim(),mode:'import',duplicate:'rename',test:importTest})});setImportModal(false);setImportText('');setImportPreview(null);flash(`导入完成：成功 ${r.success} 个，失败 ${r.failed} 个`);loadNodes()}catch(e){flash(e.message)}}
  async function loadTun(){try{let d=await api('/api/tun/config');let st=await api('/api/tun/status').catch(()=>({}));let ifaces=await api('/api/tun/interfaces').then(r=>r.interfaces||[]).catch(()=>[]);let cfg=d.config||{};setTunIfaces(ifaces);setTun({...d,status:st});setTunForm({name:cfg.name||'tun0',MTU:cfg.MTU||1500,gateway:(cfg.gateway||['172.19.0.1']).join(','),DNS:(cfg.DNS||['8.8.8.8','1.1.1.1']).join(','),autoOutboundsInterface:cfg.autoOutboundsInterface||'',autoStart:String(!!cfg.autoStart)})}catch(e){setTun({error:e.message,config:{}})}}
  async function saveTun(){try{await api('/api/tun/config',{method:'POST',body:JSON.stringify({name:tunForm.name,MTU:+tunForm.MTU,gateway:tunForm.gateway.split(',').map(x=>x.trim()).filter(Boolean),DNS:tunForm.DNS.split(',').map(x=>x.trim()).filter(Boolean),autoOutboundsInterface:tunForm.autoOutboundsInterface,autoStart:tunForm.autoStart==='true'})});flash('TUN 设置已保存');loadTun()}catch(e){flash(e.message)}}
  async function tunAct(a){if(a==='start'&&!confirm('TUN 会接管本机路由，确认启用？'))return;if(a==='cleanup'&&!confirm('强制清理 TUN 残留？'))return;try{await api('/api/tun/'+a,{method:'POST'});flash('操作完成');setTimeout(refreshAll,1000)}catch(e){flash(e.message)}}
  async function loadTraffic(){try{let d=await api('/api/traffic');setTraffic(d);let h=await api('/api/traffic/history').catch(()=>({history:[]}));setHistory(h.history||[])}catch(e){setTraffic({error:e.message})}}
  async function loadEnhance(){await Promise.allSettled([loadAuto(),loadNotify(),loadTrend()])}
  async function loadAuto(){try{let d=await api('/api/auto-select'),c=d.config||{};setAuto(d);setAutoForm({enabled:!!c.enabled,stableCount:c.stableCount||3,minInterval:Math.round((c.minIntervalMs||30000)/1000),avgWindow:c.avgWindow||5,maxLatency:c.maxLatency||5000})}catch(e){setAuto({error:e.message,config:{}})}}
  async function saveAuto(){try{await api('/api/auto-select/config',{method:'POST',body:JSON.stringify({enabled:autoForm.enabled,stableCount:+autoForm.stableCount,minIntervalMs:+autoForm.minInterval*1000,avgWindow:+autoForm.avgWindow,maxLatency:+autoForm.maxLatency})});flash('自动选优已保存');loadAuto()}catch(e){flash(e.message)}}
  async function autoNow(){try{let d=await api('/api/auto-select/now',{method:'POST'});flash('已切换到 '+(d.optimal||'-'));loadNodes();loadAuto()}catch(e){flash(e.message)}}
  async function loadNotify(){try{let d=await api('/api/notify/config'),c=d.config||{},ch=c.channels||{};setNotify(d);setNotifyForm({tg:!!ch.telegram?.enabled,tgToken:'',tgChat:ch.telegram?.chatId||'',wx:!!ch.wechatWork?.enabled,wxUrl:'',sc:!!ch.serverchan?.enabled,scKey:''});let l=await api('/api/notify/log').catch(()=>({log:[]}));setNotifyLog(l.log||[])}catch(e){setNotify({error:e.message,config:{channels:{}}})}}
  async function saveNotify(){try{let body={channels:{telegram:{enabled:notifyForm.tg,chatId:notifyForm.tgChat.trim()},wechatWork:{enabled:notifyForm.wx},serverchan:{enabled:notifyForm.sc}},rules:{}};if(notifyForm.tgToken.trim())body.channels.telegram.botToken=notifyForm.tgToken.trim();if(notifyForm.wxUrl.trim())body.channels.wechatWork.webhookUrl=notifyForm.wxUrl.trim();if(notifyForm.scKey.trim())body.channels.serverchan.sendKey=notifyForm.scKey.trim();await api('/api/notify/config',{method:'POST',body:JSON.stringify(body)});flash('通知配置已保存');loadNotify()}catch(e){flash(e.message)}}
  async function testNotify(){try{await api('/api/notify/test',{method:'POST'});flash('测试通知已发送/已尝试');loadNotify()}catch(e){flash(e.message)}}
  async function loadTrend(){try{let h=await api('/api/history?hours=168');setTrend(h.history||{})}catch(e){setTrend({error:e.message})}}
  async function loadDiagnose(){try{let d=await api('/api/tun/diagnose');setDiag(d)}catch(e){setDiag({error:e.message})}try{let b=await api('/api/tun/backup');setTunBak((b.instructions||[]).join('\n'))}catch(e){setTunBak(e.message)}}
  async function restoreNet(){try{let r=await api('/api/tun/restore',{method:'POST'});flash(r.message||'网络恢复已执行')}catch(e){flash(e.message)}} async function downloadDiag(){try{let r=await fetch('/api/tun/diagnostic-package',{headers:{Authorization:'Bearer '+token}});if(!r.ok)throw Error('HTTP '+r.status);let blob=await r.blob(),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`xray-proxy-native-diagnostic-${__APP_VERSION__}.json`;a.click();setTimeout(()=>URL.revokeObjectURL(url),1000);flash('诊断包已生成')}catch(e){flash(e.message)}}
  async function loadLogs(){try{let d=await api('/api/logs');let text=Array.isArray(d.logs)?d.logs.join('\n'):(d.content||d.logs||'');setLogs(text||'暂无日志')}catch(e){setLogs('日志读取失败：'+e.message)}}
  function exportBak(){let qs=bakPwd?('?password='+encodeURIComponent(bakPwd)+'&compress=true'):'';location.href='/api/backup/export'+qs}
  async function importBak(){try{if(!bakFile)throw Error('请选择备份文件');let text=await bakFile.text();await api('/api/backup/import',{method:'POST',body:JSON.stringify({data:text,password:bakPwd2||undefined})});flash('导入完成');setBakFile(null);setBakPreview(null);refreshAll()}catch(e){flash(e.message)}} async function setBakFile2(file){setBakFile(file);if(!file){setBakPreview(null);return}try{let text=await file.text();let data=JSON.parse(text);let outbounds=(data.config?.outbounds||[]).length;setBakPreview({outbounds,version:data.version||'-',createdAt:data.exportedAt||'-'})}catch(e){setBakPreview({error:'无法解析备份文件'})}}
  async function resetCfg(){if(!confirm('恢复默认配置？'))return;try{await api('/api/backup/reset',{method:'POST'});flash('已恢复默认');refreshAll()}catch(e){flash(e.message)}}
  const run=!!status.running, starting=!!status.starting; const tunEnabled=!!(tun.status?.enabled||tun.config?.enabled||tun.device?.exists); const total=traffic.total||{}; const down=total.down??traffic.downlink??traffic.down??0, up=total.up??traffic.uplink??traffic.up??0; const activeNode=sel||nodes[0];
  if(!authed)return <Login setup={setup} pwd={pwd} setPwd={setPwd} login={login} err={loginErr} clear={()=>{localStorage.removeItem(tokenKey);localStorage.removeItem(refreshKey);setLoginErr('登录缓存已清除，请重新输入密码')}}/>;
  return <div className="appShell"><aside className="side"><div className="brand"><div className="brandIcon"><Globe2 size={25}/></div><div><b>Xray 代理</b><span>网络代理管理</span></div></div><nav>{NAV.map(([id,t,Icon])=><button key={id} onClick={()=>setView(id)} className={view===id?'active':''}><Icon size={18}/><span>{t}</span></button>)}</nav><div className="sideCard"><b>运行端口</b><p><span>入口</span><strong>2088</strong></p><p><span>SOCKS</span><strong>10808</strong></p><p><span>HTTP</span><strong>10809</strong></p><p><span>TUN</span><strong>手动</strong></p></div></aside><main className="main"><header className="top"><div><h1>{navMeta[view].title}</h1><p>{navMeta[view].sub}</p></div><div className="topActions"><StatusPill state={run?'ok':(starting?'warn':'bad')}>{starting?'启动中':(run?'运行中':'已停止')}</StatusPill><Button size="sm" icon={Copy} onClick={()=>copyText('socks5://'+location.hostname+':10808')}>SOCKS</Button><Button size="sm" icon={Copy} onClick={()=>copyText('http://'+location.hostname+':10809')}>HTTP</Button><Button size="sm" icon={theme==='dark'?Sun:Moon} onClick={()=>setTheme(theme==='dark'?'light':'dark')}>{theme==='dark'?'浅色':'深色'}</Button><Button kind="green" size="sm" icon={Play} onClick={()=>runAction('start')}>启动</Button><Button kind="red" size="sm" icon={Square} onClick={()=>runAction('stop')}>停止</Button><Button size="sm" icon={RefreshCw} onClick={()=>runAction('restart')}>重启</Button></div></header><div className="mobileNav">{NAV.map(([id,t])=><button key={id} onClick={()=>setView(id)} className={view===id?'active':''}>{t}</button>)}</div><section className="page">{view==='dash'&&<Dashboard {...{run,starting,nodes,allNodes,tunEnabled,down,up,activeNode,logs,status,refreshAll,setView,busy}}/>}{view==='nodes'&&<Nodes {...{nodes,allNodes,sel,setSel,openNode,toggleNode,delNode,testNode,testAll,setImportModal,nodeSearch,setNodeSearch,nodeSort,setNodeSort,nodeChecked,setNodeChecked,nodeLatency,nodeLabels,saveLabels,testNodeWithLatency,batchToggle,batchDelete,moveNode,setSubModal}}/>}{view==='network'&&<NetworkPage {...{tun,tunEnabled,tunForm,setTunForm,saveTun,tunAct,tunIfaces,setConfirmTun}}/>}{view==='traffic'&&<TrafficPage {...{traffic,history,down,up,trafficRange,setTrafficRange}}/>}{view==='enhance'&&<EnhancePage {...{auto,autoForm,setAutoForm,saveAuto,autoNow,notifyForm,setNotifyForm,saveNotify,testNotify,notifyLog,trend}}/>}{view==='diagnose'&&<DiagnosePage {...{diag,tunBak,downloadDiag,restoreNet,curlResult,curlTest,geoStatus,updateGeo,quota,setQuota,saveQuota,quotaStatus,routingRules,setRoutingRules,routingDomainStrategy,setRoutingDomainStrategy,saveRouting,nodes}}/>}{view==='logs'&&<LogsPage {...{logs,loadLogs,logSearch,setLogSearch,logAutoScroll,setLogAutoScroll,copyText}}/>} {view==='backup'&&<BackupPage {...{bakFile,bakPreview,bakPwd,setBakFile:setBakFile2,setBakPwd,exportBak,bakPwd2,setBakPwd2,importBak,resetCfg}}/>}{view==='settings'&&<SettingsPage logout={logout} refreshAll={refreshAll}/>}</section><footer><span>{foot}</span><span>v{__APP_VERSION__}</span></footer></main>{toast&&<div className="toast">{toast}</div>}{nodeModal&&<NodeModal {...{nodeForm,setNodeForm,saveNode,close:()=>setNodeModal(false),editing:!!sel}}/>}{importModal&&<ImportModal {...{importText,setImportText,importPreview,previewImport,importLinks,importTest,setImportTest,close:()=>setImportModal(false)}}/>}{subModal&&<SubscriptionModal {...{subscriptions,addSub,runSub,delSub,close:()=>setSubModal(false)}}/>}{confirmTun&&<ConfirmModal {...{title:confirmTun.title,msg:confirmTun.msg,onConfirm:()=>{tunAct(confirmTun.action);setConfirmTun(null)},close:()=>setConfirmTun(null)}}/>}</div>
}
function Aurora(){return <div className="aurora"><span/><span/><span/></div>}
function Login({setup,pwd,setPwd,login,err,clear}){return <div className="loginScreen"><div className="loginPanel"><div className="loginIcon"><ShieldCheck size={34}/></div><h1>Xray 代理</h1><p>{setup?'首次使用：设置一个管理密码':'请输入管理密码进入控制台'}</p><input type="password" value={pwd} onChange={e=>setPwd(e.target.value)} onKeyDown={e=>{if(e.key==='Enter')login()}} placeholder="管理密码" autoFocus/><Button kind="primary" icon={Lock} onClick={login}>进入控制台</Button>{err&&<div className="errorText">{err}</div>}<button className="ghostLink" onClick={clear}>清除登录缓存</button></div></div>}
function Dashboard({run,starting,nodes,allNodes,tunEnabled,down,up,activeNode,logs,refreshAll,setView,busy}){
  const posture=run&&nodes.length?(tunEnabled?'全局增强':'安全代理'):'待配置';
  const readiness=(run?34:0)+(nodes.length?33:0)+(tunEnabled?18:10)+15;
  const recent=(logs||'暂无日志').split('\n').slice(-8).join('\n');
  return <div className="dashGrid proDash"><section className="hero proHero"><div><div className="eyebrow">Xray 代理控制台</div><h2>{run?'代理服务运行中':starting?'代理服务启动中':'代理服务未启动'}</h2><p>{activeNode?`当前链路：${activeNode.tag} · ${proto(activeNode)} · ${addr(activeNode)}:${port(activeNode)}`:'当前链路：未配置节点'}</p><div className="heroBtns"><Button kind="primary" icon={Network} onClick={()=>setView('nodes')}>管理节点</Button><Button icon={Wifi} onClick={()=>setView('network')}>网络模式</Button><Button icon={RefreshCw} onClick={refreshAll}>{busy?'刷新中':'刷新'}</Button></div></div></section><div className="commandDeck"><MiniCommand title="服务状态" value={starting?'启动中':run?'在线':'离线'} tone={run?'green':'red'} icon={run?Play:Square}/><MiniCommand title="节点资产" value={`${nodes.length}/${allNodes.length}`} tone="blue" icon={Boxes}/><MiniCommand title="安全姿态" value={posture} tone={tunEnabled?'amber':'green'} icon={ShieldCheck}/><MiniCommand title="吞吐合计" value={fmtBytes(down+up)} tone="violet" icon={Activity}/></div><Card title="链路拓扑" sub="从用户入口到节点出口的实时视图" icon={Network} className="topologyCard"><Topology run={run} tunEnabled={tunEnabled} node={activeNode}/></Card><Card title="控制面板" sub="高频动作和安全建议" icon={Rocket} className="controlCard"><div className="readiness"><div><b>{Math.min(100,readiness)}%</b><span>就绪度</span></div><i style={{'--p':Math.min(100,readiness)+'%'}}/></div><div className="actionMatrix"><button onClick={()=>setView('nodes')}><Network size={17}/><b>节点资产</b><span>导入 / 测速 / 切换</span></button><button onClick={()=>setView('network')}><Wifi size={17}/><b>网络模式</b><span>SOCKS/HTTP/TUN</span></button><button onClick={()=>setView('diagnose')}><LifeBuoy size={17}/><b>安全诊断</b><span>TUN / 日志 / 回滚</span></button></div></Card><div className="insights proInsights"><Info tone="green" title="安全默认" text="SOCKS/HTTP 优先，不自动接管路由"/><Info tone="blue" title="本地控制" text="所有管理操作在 fnOS 本机完成"/><Info tone="amber" title="TUN 手动" text="高级透明代理必须手动确认"/></div><div className="metrics"><Metric title="运行状态" value={starting?'启动中':run?'运行中':'停止'} tone={run?'green':'red'}/><Metric title="可用节点" value={nodes.length} sub={`出站 ${allNodes.length}`}/><Metric title="TUN 模式" value={tunEnabled?'启用':'手动'} tone={tunEnabled?'green':'amber'}/><Metric title="下行 / 上行" value={`${fmtBytes(down)} / ${fmtBytes(up)}`} tone="blue"/></div><Card title="最近日志" sub="运行态摘要" icon={TerminalSquare} className="darkCard logPreview"><pre>{recent}</pre></Card></div>}
function MiniCommand({title,value,tone,icon:Icon}){return <div className={'miniCommand '+tone}><span><Icon size={17}/>{title}</span><b>{value}</b></div>}
function Topology({run,tunEnabled,node}){return <div className="topology"><div className="topNode"><Globe2 size={20}/><b>应用入口</b><span>2088</span></div><ChevronRight/><div className="topNode"><ShieldCheck size={20}/><b>{tunEnabled?'TUN + HTTP/SOCKS':'HTTP/SOCKS'}</b><span>{tunEnabled?'透明代理启用':'默认安全模式'}</span></div><ChevronRight/><div className="topNode"><Server size={20}/><b>{node?.tag||'未选择节点'}</b><span>{node?`${proto(node)} · ${addr(node)}:${port(node)}`:'导入节点后激活'}</span></div><ChevronRight/><div className={'topNode '+(run?'online':'offline')}><Rocket size={20}/><b>{run?'出口在线':'出口离线'}</b><span>{run?'链路可用':'等待启动'}</span></div></div>}
function Info({title,text,tone}){return <div className={'info '+tone}><b>{title}</b><span>{text}</span></div>}
function Metric({title,value,sub,tone=''}){return <div className={'metric '+tone}><span>{title}</span><strong>{value}</strong>{sub&&<em>{sub}</em>}</div>}
function Nodes({nodes,allNodes,sel,setSel,openNode,toggleNode,delNode,testNode,testAll,setImportModal,nodeSearch,setNodeSearch,nodeSort,setNodeSort,nodeChecked,setNodeChecked,nodeLatency,nodeLabels,saveLabels,testNodeWithLatency,batchToggle,batchDelete,moveNode,setSubModal}){
  const enabled=nodes.filter(n=>n.enabled!==false).length;
  const disabled=nodes.length-enabled;
  const protocols=[...new Set(nodes.map(n=>proto(n)).filter(Boolean))].slice(0,4);
  let filtered=nodes.map((n,idx)=>({n,idx})).filter(({n})=>{if(!nodeSearch)return true;const q=nodeSearch.toLowerCase();return (n.tag||'').toLowerCase().includes(q)||(proto(n)||'').toLowerCase().includes(q)||(addr(n)||'').toLowerCase().includes(q)||((nodeLabels[n.tag]||[]).some(l=>l.toLowerCase().includes(q)))});
  if(nodeSort==='latency')filtered=[...filtered].sort((a,b)=>{const la=nodeLatency[a.n.tag],lb=nodeLatency[b.n.tag];const va=typeof la==='number'?la:99999;const vb=typeof lb==='number'?lb:99999;return va-vb});
  else if(nodeSort==='name')filtered=[...filtered].sort((a,b)=>(a.n.tag||'').localeCompare(b.n.tag||''));
  else if(nodeSort==='protocol')filtered=[...filtered].sort((a,b)=>(proto(a.n)||'').localeCompare(proto(b.n)||''));
  const protoColor=p=>({vless:'protoVless',vmess:'protoVmess',trojan:'protoTrojan',shadowsocks:'protoSs',ss:'protoSs'}[p]||'protoOther');
  const latencyClass=ms=>typeof ms!=='number'?'lat-na':(ms<200?'lat-good':ms<500?'lat-warn':'lat-bad');
  const allChecked=filtered.length>0&&filtered.every(({n})=>nodeChecked.has(n.tag));
  function toggleCheck(tag){const next=new Set(nodeChecked);if(next.has(tag))next.delete(tag);else next.add(tag);setNodeChecked(next)}
  function toggleAllCheck(){if(allChecked){setNodeChecked(new Set())}else{setNodeChecked(new Set(filtered.map(({n})=>n.tag)))}}
  function onDragStart(e,idx){e.dataTransfer.setData('text/plain',String(idx));e.dataTransfer.effectAllowed='move'}
  function onDragOver(e){e.preventDefault();e.dataTransfer.dropEffect='move'}
  function onDrop(e,toIdx){e.preventDefault();const fromIdx=parseInt(e.dataTransfer.getData('text/plain'));if(!isNaN(fromIdx)&&fromIdx!==toIdx)moveNode(fromIdx,toIdx)}
  return <div className="nodesPage"><div className="sectionHero"><div><span>节点资产</span><h2>节点资产中心</h2><p>统一管理订阅、手动节点、测速、启停和原始配置。</p></div><div className="row wrap"><Button icon={GitBranch} onClick={()=>setSubModal(true)}>订阅管理</Button><Button icon={Zap} onClick={testAll}>批量测速</Button><Button icon={Upload} onClick={()=>setImportModal(true)}>导入订阅</Button><Button kind="primary" icon={Plus} onClick={()=>openNode(null)}>新增节点</Button></div></div><div className="commandDeck pageDeck"><MiniCommand title="可管理" value={nodes.length} tone="blue" icon={Boxes}/><MiniCommand title="已启用" value={enabled} tone="green" icon={CheckCircle2}/><MiniCommand title="已停用" value={disabled} tone="amber" icon={Square}/><MiniCommand title="协议" value={protocols.join(' / ')||'-'} tone="violet" icon={Network}/></div><div className="nodeToolbar"><div className="searchBox grow"><Search size={14}/><input value={nodeSearch} onChange={e=>setNodeSearch(e.target.value)} placeholder="搜索节点名/协议/地址/标签"/></div><select value={nodeSort} onChange={e=>setNodeSort(e.target.value)} className="sel"><option value="default">默认排序</option><option value="latency">按延迟</option><option value="name">按名称</option><option value="protocol">按协议</option></select><Button size="sm" disabled={!nodeChecked.size} icon={CheckCircle2} onClick={()=>batchToggle(true)}>批量启用</Button><Button size="sm" disabled={!nodeChecked.size} icon={Square} onClick={()=>batchToggle(false)}>批量停用</Button><Button size="sm" kind="red" disabled={!nodeChecked.size} icon={Trash2} onClick={batchDelete}>批量删除</Button>{nodeChecked.size?<span className="batchInfo">已选 {nodeChecked.size}</span>:null}</div><div className="twoCol wideLeft"><Card title="节点列表" sub={(`显示 ${filtered.length} / ${nodes.length}，出站 ${allNodes.length}`)} icon={Boxes} action={filtered.length?<label className="check"><input type="checkbox" checked={allChecked} onChange={toggleAllCheck}/><span>全选</span></label>:null}>{filtered.length? <div className="nodeList premiumNodeList">{filtered.map(({n,idx:realIdx})=>{const lat=nodeLatency[n.tag];const labels=nodeLabels[n.tag]||[];const p=proto(n);return <div key={n.tag} className={'nodeCard premiumNode '+protoColor(p)+' '+(sel?.tag===n.tag?'active':'')+(n.enabled===false?' off':'')} draggable={nodeSort==='default'} onDragStart={e=>onDragStart(e,realIdx)} onDragOver={onDragOver} onDrop={e=>onDrop(e,realIdx)} onClick={()=>setSel(n)}><span className="statDot" data-state={n.enabled===false?'off':'on'}/><input type="checkbox" className="nodeCheck" checked={nodeChecked.has(n.tag)} onChange={e=>{e.stopPropagation();toggleCheck(n.tag)}} onClick={e=>e.stopPropagation()}/><div className={'nodeAvatar '+protoColor(p)}>{(p||'?').slice(0,2).toUpperCase()}</div><div className="nodeMain"><b>{n.tag}{labels.map(l=><i key={l} className="labelTag">{l}</i>)}</b><span className="mono">{p} · {addr(n)}:{port(n)}</span><em>{n.streamSettings?.network||'tcp'} / {n.streamSettings?.security||'none'}</em></div><div className="nodeMeta"><span className={'latBadge '+latencyClass(lat)}>{typeof lat==='number'?lat+'ms':(lat==='fail'?'失败':'-')}</span><button className="iconBtn" title="测速" onClick={e=>{e.stopPropagation();testNodeWithLatency(n.tag)}}><Zap size={14}/></button></div></div>;})}</div>:<Empty title="没有匹配的节点" sub="尝试清空搜索或新增节点。"/>}</Card><Card title="节点详情" sub="配置、状态和操作" icon={Server} className="nodeDetailCard">{sel?<div className="detail"><div className="detailHero premiumDetail"><div className={'nodeAvatar big '+protoColor(proto(sel))}>{proto(sel).slice(0,2).toUpperCase()}</div><div><h3>{sel.tag}</h3><p className="mono">{proto(sel)} · {addr(sel)}:{port(sel)}</p></div><StatusPill state={sel.enabled===false?'bad':'ok'}>{sel.enabled===false?'停用':'可用'}</StatusPill></div><div className="kv kvPro"><span>协议</span><b>{proto(sel)}</b><span>网络</span><b>{sel.streamSettings?.network||'-'}</b><span>安全</span><b>{sel.streamSettings?.security||'none'}</b><span>地址</span><b className="mono">{addr(sel)}:{port(sel)}</b><span>启用</span><b>{sel.enabled===false?'否':'是'}</b><span>延迟</span><b className={'mono '+latencyClass(nodeLatency[sel.tag])}>{typeof nodeLatency[sel.tag]==='number'?nodeLatency[sel.tag]+' ms':'未测'}</b></div><div className="labelEditor"><span className="formLabel">标签</span><input type="text" placeholder="逗号分隔，如：美国,Netflix" defaultValue={(nodeLabels[sel.tag]||[]).join(',')} onBlur={e=>{const v=e.target.value.split(/[,，]/).map(x=>x.trim()).filter(Boolean);saveLabels(sel.tag,v)}}/></div><div className="row wrap"><Button icon={Zap} onClick={()=>testNodeWithLatency(sel.tag)}>测速</Button><Button icon={Save} onClick={()=>openNode(sel)}>编辑</Button><Button icon={sel.enabled===false?CheckCircle2:Square} onClick={()=>toggleNode(sel.tag,sel.enabled===false)}>{sel.enabled===false?'启用':'停用'}</Button><Button kind="red" icon={Trash2} onClick={()=>delNode(sel.tag)}>删除</Button></div><pre className="code configCode">{JSON.stringify(sel,null,2)}</pre></div>:<Empty title="选择节点" sub="点击左侧节点查看详情。"/>}</Card></div></div>}
function NetworkPage({tun,tunEnabled,tunForm,setTunForm,saveTun,tunAct,tunIfaces,setConfirmTun}){return <div className="networkPage"><div className="sectionHero safetyHero"><div><span>网络模式</span><h2>网络模式与安全边界</h2><p>默认使用 SOCKS/HTTP；TUN 属于高级透明代理，所有启用动作必须手动确认。</p></div><StatusPill state={tunEnabled?'ok':'warn'}>{tunEnabled?'TUN 已启用':'TUN 手动模式'}</StatusPill></div><div className="networkGrid"><Card title="推荐代理模式" sub="默认安全，不接管路由" icon={ShieldCheck} className="accentGreen"><div className="modeTiles premiumModes"><div><b>SOCKS</b><strong>10808</strong><span>浏览器 / 客户端代理</span></div><div><b>HTTP</b><strong>10809</strong><span>下载器 / 系统代理</span></div></div><div className="safeNote"><CheckCircle2 size={18}/>适合日常使用；不会自动修改系统路由。</div></Card><Card title="TUN 高级模式" sub="透明代理，需要手动确认" icon={Wifi} className="accentAmber" action={<StatusPill state={tunEnabled?'ok':'warn'}>{tunEnabled?'已启用':'未启用'}</StatusPill>}><div className="formGrid"><Field label="设备名"><input value={tunForm.name} onChange={e=>setTunForm({...tunForm,name:e.target.value})}/></Field><Field label="MTU"><input type="number" value={tunForm.MTU} onChange={e=>setTunForm({...tunForm,MTU:e.target.value})}/></Field><Field label="网关"><input value={tunForm.gateway} onChange={e=>setTunForm({...tunForm,gateway:e.target.value})}/></Field><Field label="DNS"><input value={tunForm.DNS} onChange={e=>setTunForm({...tunForm,DNS:e.target.value})}/></Field><Field label="出口网卡"><select value={tunForm.autoOutboundsInterface} onChange={e=>setTunForm({...tunForm,autoOutboundsInterface:e.target.value})}><option value="">自动检测</option>{tunIfaces.map(iface=><option key={iface} value={iface}>{iface}</option>)}</select></Field><Field label="自动恢复"><select value={tunForm.autoStart} onChange={e=>setTunForm({...tunForm,autoStart:e.target.value})}><option value="false">关闭</option><option value="true">开启</option></select></Field></div><div className="row wrap"><Button kind="primary" icon={Save} onClick={saveTun}>保存 TUN</Button><Button kind="green" icon={Play} onClick={()=>setConfirmTun({action:'start',title:'启用 TUN',msg:'TUN 接管整机流量，错配可能断网，是否确认？'})}>启用</Button><Button kind="red" icon={Square} onClick={()=>setConfirmTun({action:'stop',title:'停止 TUN',msg:'即将停止 TUN，恢复原网络？'})}>停止</Button><Button icon={Trash2} onClick={()=>setConfirmTun({action:'cleanup',title:'清理 TUN 残留',msg:'尝试清理残留 tun 设备和路由，是否继续？'})}>清理残留</Button></div><div className="tunSummary"><div><span>配置启用</span><b>{tun.config?.enabled?'是':'否'}</b></div><div><span>自动恢复</span><b>{tun.config?.autoStart?'开启':'关闭'}</b></div><div><span>设备</span><b>{tun.config?.name||'tun0'} · {tun.device?.exists?'存在':'未检测'}</b></div><div><span>xray</span><b>{tun.xray?.running?'运行中':'未运行'}</b></div></div></Card></div></div>}
function TrafficPage({traffic,history,down,up,trafficRange,setTrafficRange}){let inbound=traffic.inbound||{}, sorted=traffic.traffic_sorted||[];const histSlice=history.slice(-trafficRange);let max=Math.max(1,...histSlice.map(x=>(x.down||0)+(x.up||0)));return <div className="trafficGrid trafficPage"><div className="sectionHero trafficHero"><div><span>流量观测</span><h2>流量观测台</h2><p>聚合入站、节点排行和历史趋势，快速判断代理链路负载。</p></div><strong>{fmtBytes(down+up)}</strong></div><div className="metrics"><Metric title="总下行" value={fmtBytes(down)} tone="blue"/><Metric title="总上行" value={fmtBytes(up)} tone="green"/><Metric title="入站数量" value={Object.keys(inbound).length}/><Metric title="节点流量" value={sorted.length}/></div><Card title="历史趋势" sub={(`显示最近 ${trafficRange} 个样本`)} icon={Activity} className="wide" action={<div className="row"><select value={trafficRange} onChange={e=>setTrafficRange(+e.target.value)} className="sel"><option value={12}>近 12</option><option value={24}>近 24</option><option value={48}>近 48</option><option value={96}>近 96</option></select></div>}><div className="chartFrame">{histSlice.length?<SvgLine data={histSlice} max={max}/>:<Empty title="暂无历史" sub="服务运行后会生成流量历史。"/>}</div></Card><Card title="入站统计" icon={Wifi}>{Object.keys(inbound).length?<table className="proTable"><tbody>{Object.entries(inbound).map(([k,v])=><tr key={k}><td>{k}</td><td>{fmtBytes(v.down||0)}</td><td>{fmtBytes(v.up||0)}</td></tr>)}</tbody></table>:<Empty/>}</Card><Card title="节点流量排行" icon={Network}>{sorted.length?<table className="proTable"><tbody>{sorted.map(x=><tr key={x.tag}><td>{x.tag}</td><td>{fmtBytes(x.down)}</td><td>{fmtBytes(x.up)}</td></tr>)}</tbody></table>:<Empty/>}</Card></div>}
function EnhancePage({auto,autoForm,setAutoForm,saveAuto,autoNow,notifyForm,setNotifyForm,saveNotify,testNotify,notifyLog,trend}){let rows=Object.keys(trend||{}).filter(k=>k!=='error');return <div className="enhanceGrid enhancePage"><div className="sectionHero enhanceHero"><div><span>增强能力</span><h2>增强能力中心</h2><p>自动选优、通知渠道和节点趋势集中管理，让代理链路具备自我调整能力。</p></div><StatusPill state={autoForm.enabled?'ok':'warn'}>{autoForm.enabled?'自动选优开启':'自动选优关闭'}</StatusPill></div><Card title="自动选优" sub={`当前 ${auto.current||'-'} · 最优 ${auto.optimal||'-'}`} icon={Rocket}><div className="formGrid"><ToggleField label="启用自动选优" sub="按稳定次数和延迟自动选择节点" checked={autoForm.enabled} onChange={e=>setAutoForm({...autoForm,enabled:e.target.checked})}/><Field label="稳定次数"><input type="number" value={autoForm.stableCount} onChange={e=>setAutoForm({...autoForm,stableCount:e.target.value})}/></Field><Field label="间隔秒"><input type="number" value={autoForm.minInterval} onChange={e=>setAutoForm({...autoForm,minInterval:e.target.value})}/></Field><Field label="平均窗口"><input type="number" value={autoForm.avgWindow} onChange={e=>setAutoForm({...autoForm,avgWindow:e.target.value})}/></Field><Field label="最大延迟"><input type="number" value={autoForm.maxLatency} onChange={e=>setAutoForm({...autoForm,maxLatency:e.target.value})}/></Field></div><div className="row"><Button kind="primary" icon={Save} onClick={saveAuto}>保存</Button><Button icon={Zap} onClick={autoNow}>立即选优</Button></div></Card><Card title="通知中心" sub="密钥留空表示不修改" icon={Bell}><div className="formGrid"><ToggleField label="Telegram" sub="启用机器人通知" checked={notifyForm.tg} onChange={e=>setNotifyForm({...notifyForm,tg:e.target.checked})}/><Field label="Chat ID"><input value={notifyForm.tgChat} onChange={e=>setNotifyForm({...notifyForm,tgChat:e.target.value})}/></Field><Field label="Bot Token"><input value={notifyForm.tgToken} onChange={e=>setNotifyForm({...notifyForm,tgToken:e.target.value})} placeholder="留空不修改"/></Field><ToggleField label="企业微信" sub="启用企业微信 Webhook" checked={notifyForm.wx} onChange={e=>setNotifyForm({...notifyForm,wx:e.target.checked})}/><Field label="Webhook"><input value={notifyForm.wxUrl} onChange={e=>setNotifyForm({...notifyForm,wxUrl:e.target.value})} placeholder="留空不修改"/></Field><ToggleField label="Server酱" sub="启用 Server 酱推送" checked={notifyForm.sc} onChange={e=>setNotifyForm({...notifyForm,sc:e.target.checked})}/><Field label="SendKey"><input value={notifyForm.scKey} onChange={e=>setNotifyForm({...notifyForm,scKey:e.target.value})} placeholder="留空不修改"/></Field></div><div className="row"><Button kind="primary" icon={Save} onClick={saveNotify}>保存通知</Button><Button icon={Bell} onClick={testNotify}>测试通知</Button></div></Card><Card title="节点趋势" icon={Activity}>{rows.length?<table className="proTable"><tbody>{rows.slice(0,12).map(k=><tr key={k}><td>{k}</td><td>{Array.isArray(trend[k])?trend[k].length:'-' } 次记录</td></tr>)}</tbody></table>:<Empty title="暂无趋势"/>}</Card><Card title="通知日志" icon={TerminalSquare} className="darkCard"><pre>{notifyLog.length?notifyLog.slice(-12).map(x=>typeof x==='string'?x:JSON.stringify(x)).join('\n'):'暂无通知日志'}</pre></Card></div>}
function DiagnosePage({diag,tunBak,downloadDiag,restoreNet,curlResult,curlTest,geoStatus,updateGeo,quota,setQuota,saveQuota,quotaStatus,routingRules,setRoutingRules,routingDomainStrategy,setRoutingDomainStrategy,saveRouting,nodes}){let steps=diag?.checks||diag?.steps||[];return <div className="diagnosePage twoCol"><div className="sectionHero diagnoseHero"><div><span>安全诊断</span><h2>安全诊断中心</h2><p>面向 TUN、路由、日志和回滚的诊断入口，避免高级模式导致网络不可用。</p></div><Button icon={Download} onClick={downloadDiag}>下载诊断包</Button></div><Card title="安全向导" sub="TUN 使用前建议确认" icon={LifeBuoy}>{['先使用 SOCKS/HTTP 验证节点可用','开启 TUN 前确认已有可用节点','如网络异常，先停止 TUN 再清理残留','必要时下载诊断包发送给维护者'].map((x,i)=><div className="check" key={x}><span>{i+1}</span>{x}</div>)}</Card><Card title="诊断结果" icon={TerminalSquare}>{diag?.error?<div className="errorText">{diag.error}</div>:steps.length?<div>{steps.map((s,i)=><div className="check" key={i}><span>{s.ok?'✓':'!'}</span>{s.name||s.title||JSON.stringify(s)}</div>)}</div>:<pre className="code">{JSON.stringify(diag||{},null,2)}</pre>}</Card><Card title="回滚提示" icon={ShieldCheck} className="wide"><pre className="code">{tunBak||'暂无回滚提示'}</pre><div style={{marginTop:12}}><Button kind="red" onClick={restoreNet}>一键恢复网络</Button></div></Card>
<Card title="curl 连通性测试" sub="通过代理或直连访问目标" icon={Globe2}><CurlTester nodes={nodes} curlResult={curlResult} curlTest={curlTest}/></Card>
<Card title="GeoIP / GeoSite 数据" sub="路由分流依赖" icon={Globe2}><div className="kv kvPro"><span>geoip.dat</span><b className="mono">{geoStatus?.geoip?.exists?(geoStatus.geoip.size_kb+' KB'):'缺失'}</b><span>geosite.dat</span><b className="mono">{geoStatus?.geosite?.exists?(geoStatus.geosite.size_kb+' KB'):'缺失'}</b></div><div className="row"><Button icon={Download} onClick={updateGeo}>一键更新</Button></div></Card>
<Card title="流量配额告警" sub="按月统计代理总流量" icon={Bell}><div className="formGrid"><Field label="启用"><select value={quota.enabled?'1':'0'} onChange={e=>setQuota({...quota,enabled:e.target.value==='1'})}><option value="0">关闭</option><option value="1">开启</option></select></Field><Field label="月配额 (GB)"><input type="number" value={quota.monthly_gb} onChange={e=>setQuota({...quota,monthly_gb:+e.target.value})}/></Field><Field label="阈值 %"><input value={(quota.notify_at||[]).join(',')} onChange={e=>setQuota({...quota,notify_at:e.target.value.split(',').map(x=>+x.trim()).filter(x=>!isNaN(x))})} placeholder="80,100"/></Field><Field label="重置日"><input type="number" min="1" max="28" value={quota.reset_day} onChange={e=>setQuota({...quota,reset_day:+e.target.value})}/></Field></div>{quotaStatus&&quotaStatus.enabled?<div className="quotaStatus"><span>本月已用 <b className="mono">{quotaStatus.used_gb} GB</b> / {quotaStatus.monthly_gb} GB ({quotaStatus.percent}%)</span><div className="bar"><i style={{width:Math.min(100,quotaStatus.percent)+'%'}}/></div></div>:null}<div className="row"><Button kind="primary" icon={Save} onClick={saveQuota}>保存配额</Button></div></Card>
<Card title="路由规则" sub="按域名/IP/端口将流量导向 proxy/direct/block" icon={GitBranch} className="wide"><div className="formGrid"><Field label="域名策略"><select value={routingDomainStrategy} onChange={e=>setRoutingDomainStrategy(e.target.value)}><option>AsIs</option><option>IPIfNonMatch</option><option>IPOnDemand</option></select></Field></div><table className="proTable ruleTable"><thead><tr><th>类型</th><th>匹配</th><th>动作</th><th></th></tr></thead><tbody>{routingRules.map((r,i)=><tr key={i}><td><select value={r.type} onChange={e=>{const c=[...routingRules];c[i]={...r,type:e.target.value};setRoutingRules(c)}}><option value="domain">domain</option><option value="ip">ip</option><option value="port">port</option></select></td><td><input value={r.value} onChange={e=>{const c=[...routingRules];c[i]={...r,value:e.target.value};setRoutingRules(c)}} placeholder="例：geosite:cn / 192.168.0.0/16 / 80,443"/></td><td><select value={r.action} onChange={e=>{const c=[...routingRules];c[i]={...r,action:e.target.value};setRoutingRules(c)}}><option value="proxy">proxy</option><option value="direct">direct</option><option value="block">block</option></select></td><td><button className="iconBtn" onClick={()=>setRoutingRules(routingRules.filter((_,k)=>k!==i))}><X size={14}/></button></td></tr>)}</tbody></table><div className="row"><Button size="sm" icon={Plus} onClick={()=>setRoutingRules([...routingRules,{type:'domain',value:'',action:'direct'}])}>添加规则</Button><Button kind="primary" size="sm" icon={Save} onClick={saveRouting}>保存规则</Button></div></Card>
</div>}
function LogsPage({logs,loadLogs,logSearch,setLogSearch,logAutoScroll,setLogAutoScroll,copyText}){const [filter,setFilter]=useState('all');const normalized=(logs||'暂无日志').replace(/\\n/g,'\n');const allLines=normalized.split('\n');const lines=allLines.filter(line=>{if(filter==='error'&&!/error|fail|失败|错误/i.test(line))return false;if(filter==='warn'&&!/warn|警告/i.test(line))return false;if(filter==='info'&&/error|fail|失败|错误|warn|警告/i.test(line))return false;if(logSearch&&!line.toLowerCase().includes(logSearch.toLowerCase()))return false;return true});const preRef=React.useRef(null);useEffect(()=>{if(logAutoScroll&&preRef.current){preRef.current.scrollTop=preRef.current.scrollHeight}},[lines.length,logAutoScroll]);return <div className="logsPage"><div className="sectionHero logHero"><div><span>日志中心</span><h2>日志中心</h2><p>查看运行状态、错误和诊断线索。</p></div><div className="row wrap"><Button size="sm" kind={filter==='error'?'red':''} onClick={()=>setFilter(filter==='error'?'all':'error')}>错误</Button><Button size="sm" kind={filter==='warn'?'primary':''} onClick={()=>setFilter(filter==='warn'?'all':'warn')}>警告</Button><Button size="sm" kind={filter==='info'?'primary':''} onClick={()=>setFilter(filter==='info'?'all':'info')}>信息</Button><Button icon={RefreshCw} onClick={loadLogs}>刷新</Button><Button icon={Copy} onClick={()=>copyText(lines.join('\n'))}>复制</Button></div></div><Card title="实时日志" sub={lines.length+' 行'} icon={TerminalSquare} className="darkCard full logConsole" action={<div className="row"><div className="searchBox"><Search size={14}/><input value={logSearch} onChange={e=>setLogSearch(e.target.value)} placeholder="搜索内容"/></div><label className="check"><input type="checkbox" checked={logAutoScroll} onChange={e=>setLogAutoScroll(e.target.checked)}/><span>自动滚动</span></label></div>}><pre ref={preRef}>{lines.map((line,i)=><span key={i} className={/error|fail|失败|错误/i.test(line)?'err':/warn|警告/i.test(line)?'warn':''}><i className="lineNo">{i+1}</i>{line}\n</span>)}</pre></Card></div>}
function BackupPage({bakFile,bakPreview,bakPwd,setBakFile,setBakPwd,exportBak,bakPwd2,setBakPwd2,importBak,resetCfg}){return <div className="backupPage twoCol"><div className="sectionHero backupHero"><div><span>备份保险库</span><h2>备份保险库</h2><p>导出、加密、恢复和重置配置，避免节点资产和代理配置丢失。</p></div><ShieldCheck size={42}/></div><Card title="导出备份" sub="可选加密密码" icon={Download}><Field label="加密密码"><input type="password" value={bakPwd} onChange={e=>setBakPwd(e.target.value)} placeholder="留空则明文导出"/></Field><Button kind="primary" icon={Download} onClick={exportBak}>导出配置</Button></Card><Card title="导入备份" sub="恢复前请确认来源可信" icon={Upload}><Field label="备份文件"><label className="filePicker"><input type="file" onChange={e=>setBakFile(e.target.files?.[0]||null)}/><span>选择备份文件</span><em>{bakFile?.name || '未选择文件'}</em></label></Field>{bakPreview&&<div className="bakPreview">{bakPreview.error?<span className="err">{bakPreview.error}</span>:<><b>备份预览</b><span>出站节点: {bakPreview.outbounds}</span><span>版本: {bakPreview.version}</span><span>创建时间: {bakPreview.createdAt}</span></>}</div>}<Field label="解密密码"><input type="password" value={bakPwd2} onChange={e=>setBakPwd2(e.target.value)} placeholder="加密备份必填"/></Field><div className="row"><Button kind="primary" icon={Upload} onClick={importBak}>导入</Button><Button kind="red" icon={Trash2} onClick={resetCfg}>恢复默认</Button></div></Card></div>}
function SettingsPage({logout,refreshAll}){return <div className="settingsPage twoCol"><div className="sectionHero settingsHero"><div><span>应用设置</span><h2>应用设置</h2><p>查看版本、前端资源、资源路径和会话操作。</p></div><Settings size={42}/></div><Card title="应用信息" icon={Settings}><div className="kv kvPro"><span>版本</span><b>v{__APP_VERSION__}</b><span>前端</span><b>静态前端</b><span>资源路径</span><b>相对路径 ./assets</b><span>服务端口</span><b>2088</b></div></Card><Card title="会话" icon={Lock}><div className="row"><Button icon={RefreshCw} onClick={refreshAll}>刷新全部</Button><Button kind="red" icon={Lock} onClick={logout}>退出登录</Button></div></Card></div>}
function NodeModal({nodeForm,setNodeForm,saveNode,close,editing}){return <div className="modal"><div className="modalBox"><header><h2>{editing?'编辑节点':'新增节点'}</h2><button onClick={close}>×</button></header><div className="formGrid"><Field label="Tag"><input value={nodeForm.tag} onChange={e=>setNodeForm({...nodeForm,tag:e.target.value})}/></Field><Field label="协议"><select value={nodeForm.protocol} onChange={e=>setNodeForm({...nodeForm,protocol:e.target.value})}><option>vless</option><option>vmess</option><option>trojan</option><option>shadowsocks</option></select></Field><Field label="地址"><input value={nodeForm.address} onChange={e=>setNodeForm({...nodeForm,address:e.target.value})}/></Field><Field label="端口"><input value={nodeForm.port} onChange={e=>setNodeForm({...nodeForm,port:e.target.value})}/></Field><Field label="ID/密码" wide><input value={nodeForm.id} onChange={e=>setNodeForm({...nodeForm,id:e.target.value})}/></Field><Field label="网络"><select value={nodeForm.network} onChange={e=>setNodeForm({...nodeForm,network:e.target.value})}><option>tcp</option><option>ws</option><option>grpc</option><option>http</option></select></Field><Field label="安全"><select value={nodeForm.security} onChange={e=>setNodeForm({...nodeForm,security:e.target.value})}><option>none</option><option>tls</option><option>reality</option></select></Field><Field label="高级 JSON" wide><textarea value={nodeForm.extra} onChange={e=>setNodeForm({...nodeForm,extra:e.target.value})} placeholder='{"streamSettings":{...}}'/></Field></div><footer><Button onClick={close}>取消</Button><Button kind="primary" icon={Save} onClick={saveNode}>保存</Button></footer></div></div>}
function ImportModal({importText,setImportText,importPreview,previewImport,importLinks,importTest,setImportTest,close}){return <div className="modal"><div className="modalBox large"><header><h2>导入节点 / 订阅</h2><button onClick={close}>×</button></header><textarea className="bigText" value={importText} onChange={e=>setImportText(e.target.value)} placeholder="粘贴 vmess/vless/trojan/ss 链接或订阅 URL，支持多行"/><label className="switch"><input type="checkbox" checked={importTest} onChange={e=>setImportTest(e.target.checked)}/> 导入后测速</label>{importPreview&&<pre className="code">{JSON.stringify(importPreview,null,2)}</pre>}<footer><Button onClick={previewImport}>预览</Button><Button kind="primary" icon={Upload} onClick={importLinks}>导入</Button></footer></div></div>}

function SvgLine({data,max}){const W=900,H=160,pad=10;const N=data.length;const dx=N>1?(W-pad*2)/(N-1):0;const pts=data.map((x,i)=>{const v=(x.down||0)+(x.up||0);const y=H-pad-(v/max)*(H-pad*2);return [pad+i*dx, y]});const d=pts.map((p,i)=>(i===0?'M':'L')+p[0].toFixed(1)+' '+p[1].toFixed(1)).join(' ');const fill=d+' L '+pts[pts.length-1][0].toFixed(1)+' '+(H-pad)+' L '+pad+' '+(H-pad)+' Z';return <svg viewBox={`0 0 ${W} ${H}`} className="svgChart" preserveAspectRatio="none"><defs><linearGradient id="lg1" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor="#3b82f6" stopOpacity="0.35"/><stop offset="100%" stopColor="#3b82f6" stopOpacity="0"/></linearGradient></defs><path d={fill} fill="url(#lg1)"/><path d={d} fill="none" stroke="#3b82f6" strokeWidth="1.6"/>{pts.map((p,i)=><circle key={i} cx={p[0]} cy={p[1]} r="1.5" fill="#3b82f6"/>)}</svg>}
function CurlTester({nodes,curlResult,curlTest}){const [target,setTarget]=useState('https://www.google.com/generate_204');const [mode,setMode]=useState('proxy');return <div><div className="formGrid"><Field label="URL"><input value={target} onChange={e=>setTarget(e.target.value)}/></Field><Field label="模式"><select value={mode} onChange={e=>setMode(e.target.value)}><option value="proxy">通过代理 (SOCKS)</option><option value="direct">直连</option></select></Field></div><div className="row"><Button kind="primary" icon={Zap} onClick={()=>curlTest(target,mode)}>开始测试</Button></div>{curlResult&&(curlResult.pending?<div className="testRes">测试中…</div>:<pre className="code curlOut">{[curlResult.ok?'✓ 成功':'✗ 失败',curlResult.http_code?('HTTP '+curlResult.http_code):'',(curlResult.time_ms||curlResult.time_seconds)?((curlResult.time_ms||Math.round(curlResult.time_seconds*1000))+' ms'):'',curlResult.error||'',curlResult.output||''].filter(Boolean).join('\n')}</pre>)}</div>}
function SubscriptionModal({subscriptions,addSub,runSub,delSub,close}){const [name,setName]=useState('');const [url,setUrl]=useState('');const [hours,setHours]=useState(12);async function submit(e){e.preventDefault();if(!name||!url)return;await addSub(name,url,+hours);setName('');setUrl('')}return <div className="modal subModal" onClick={close}><div className="modalCard" onClick={e=>e.stopPropagation()}><header><h3>订阅管理</h3><button className="iconBtn" onClick={close}><X size={16}/></button></header><form className="row wrap" onSubmit={submit}><input placeholder="名称" value={name} onChange={e=>setName(e.target.value)}/><input placeholder="订阅 URL (https://...)" value={url} onChange={e=>setUrl(e.target.value)} className="grow"/><input type="number" min="1" placeholder="间隔小时" value={hours} onChange={e=>setHours(e.target.value)} style={{width:90}}/><Button kind="primary" icon={Plus} type="submit">添加</Button></form><table className="proTable subTable"><thead><tr><th>名称</th><th>URL</th><th>间隔</th><th>最近更新</th><th>下次更新</th><th>新增</th><th>状态</th><th></th></tr></thead><tbody>{subscriptions.length?subscriptions.map(s=><tr key={s.id}><td>{s.name}</td><td className="ellipsis mono" title={s.url}>{s.url}</td><td>{s.interval_hours} h</td><td className="mono">{s.last_run?new Date(s.last_run).toLocaleString():'-'}</td><td className="mono">{s.next_run?new Date(s.next_run).toLocaleString():'-'}</td><td>{s.last_added??0}</td><td title={s.last_error||''}>{s.due?'待更新 ':''}{s.last_status||'-'}</td><td><Button size="sm" icon={RefreshCw} onClick={()=>runSub(s.id)}>更新</Button> <Button size="sm" kind="red" icon={Trash2} onClick={()=>delSub(s.id)}>删除</Button></td></tr>):<tr><td colSpan="8"><Empty title="还没有订阅"/></td></tr>}</tbody></table></div></div>}
function ConfirmModal({title,msg,onConfirm,close}){return <div className="modal" onClick={close}><div className="modalCard small" onClick={e=>e.stopPropagation()}><header><h3>{title}</h3><button className="iconBtn" onClick={close}><X size={16}/></button></header><div style={{padding:'14px 0 6px'}}><AlertTriangle size={18} style={{color:'#f59e0b',verticalAlign:'middle',marginRight:6}}/>{msg}</div><footer><Button onClick={close}>取消</Button><Button kind="primary" onClick={onConfirm}>确认</Button></footer></div></div>}

createRoot(document.getElementById('root')).render(<App/>);
